// Loop over input items and add a new field called 'myNewField' to the JSON of each one
const raw = $json.output;
const d = JSON.parse(raw);

const skillRows = [];
for (let i = 1; i <= 6; i++) {
  if (d[`SKILL_CATEGORY_${i}`]) {
    skillRows.push(`**${d[`SKILL_CATEGORY_${i}`]}:** ${d[`SKILL_CONTENT_${i}`]}`);
  }
}

const projectBlocks = [];
for (let i = 1; i <= 6; i++) {
  if (d[`PROJECT_TITLE_${i}`]) {
    projectBlocks.push(
      `### Project ${i}: ${d[`PROJECT_TITLE_${i}`]}\n` +
      `${d[`PROJECT_DESCRIPTION_${i}`]}\n\n` +
      `**Responsibilities:**\n${d[`PROJECT_RESPONSIBILITIES_${i}`]}\n\n` +
      `**Tech Stack:** ${d[`PROJECT_TECHSTACK_${i}`]}`
    );
  }
}

const eduRows = [];
for (let i = 1; i <= 2; i++) {
  if (d[`EDUCATION_DEGREE_${i}`]) {
    eduRows.push(`- ${d[`EDUCATION_DEGREE_${i}`]} — ${d[`EDUCATION_INSTITUTE_${i}`]} (${d[`EDUCATION_YEAR_${i}`]})`);
  }
}

const preview = [
  `## 👤 ${d.CANDIDATE_NAME} — ${d.CANDIDATE_ROLE}`,
  `---`,
  `### Professional Summary`,
  d.PROFESSIONAL_SUMMARY,
  `---`,
  `### Skills`,
  skillRows.join('\n'),
  `---`,
  `### Projects`,
  projectBlocks.join('\n\n---\n'),
  `---`,
  `### Education`,
  eduRows.join('\n')
].join('\n\n');

return [{ json: { 
  fields: d,
  preview: preview + "\n\n---\n\nHere's the formatted content! Please review each section. You can ask me to make changes — for example: *'Make the summary more concise'* or *'Add Django to Project 2's tech stack'*. When you're happy, just say **'Looks good'** and I'll create the Google Doc.",
  raw_resume_text: $('Extract from File').item.json.text
}}];

