// Loop over input items and add a new field called 'myNewField' to the JSON of each one
const text = $json.text || "";
const lower = text.toLowerCase();

// Check for resume-like keywords
const resumeKeywords = [
  "experience", "education", "skills", "project", 
  "work history", "employment", "qualification",
  "responsibilities", "objective", "summary",
  "bachelor", "master", "degree", "university",
  "developer", "engineer", "manager", "analyst"
];

const matchCount = resumeKeywords.filter(kw => lower.includes(kw)).length;

if (matchCount < 5) {
  // Not a resume — flag it
  return [{ json: { 
    is_resume: false, 
    text: $json.text,
    reply: "Hmm, that doesn't look like a resume to me 🤔 I can only work with candidate resumes — even a rough one works! Could you upload the right PDF?"
  }}];
}

return [{ json: { is_resume: true, text: $json.text } }];

const raw = $json.output;
const parsed = JSON.parse(raw);

const docUrl = $('Build Placeholder Requests').item.json.webViewLink;

let reply = `Your formatted resume is ready! 🎉 Click below to open it.
📄 Resume Link:
${docUrl}
`;

if (parsed.overall_fit !== null) {
  reply += `---

📊 ATS ANALYSIS

Overall Fit: ${parsed.overall_fit}%
ATS Score: ${parsed.ats_score}%

✅ Strong Matches:
- ${parsed.strong_matches.join('
- ')}

⚠️ Gaps:
- ${parsed.gaps.join('
- ')}`;
} else {
  reply += 'No JD provided — ATS analysis skipped.';
}

return [{ json: { reply, doc_url: docUrl, stage: 'complete' } }];

